<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h1 class="mb-4">Job Application</h1>

    @* Step Indicator Bar *@
    <nav class="d-flex justify-content-between mb-4 position-relative">
        <div class="position-absolute" style="top: 20px; left: 40px; right: 40px; height: 2px; background: #dee2e6; z-index: 0;"></div>
        @for (int i = 0; i < _stepNames.Length; i++)
        {
            var stepIndex = i;
            var isCompleted = stepIndex < _currentStep;
            var isCurrent = stepIndex == _currentStep;
            var isFuture = stepIndex > _currentStep;
            <div class="text-center position-relative" style="z-index: 1; flex: 1;">
                <button class="btn rounded-circle d-inline-flex align-items-center justify-content-center p-0 @(isCurrent ? "btn-primary" : isCompleted ? "btn-success" : "btn-outline-secondary")"
                        style="width: 40px; height: 40px; font-size: 0.85rem;"
                        disabled="@(isFuture || _submitted)"
                        @onclick="() => GoToStep(stepIndex)">
                    @if (isCompleted)
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </button>
                <div class="mt-1 small @(isFuture ? "text-muted" : "")">@_stepNames[stepIndex]</div>
            </div>
        }
    </nav>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger alert-dismissible" role="alert">
            @_errorMessage
            <button type="button" class="btn-close" @onclick="() => _errorMessage = null"></button>
        </div>
    }

    @if (_submitted)
    {
        <div class="alert alert-success text-center py-5">
            <h3>🎉 Application Submitted!</h3>
            <p class="lead mt-3">Your application has been received.</p>
            <p>Your application ID is: <strong>@_applicationId</strong></p>
        </div>
    }
    else
    {
        @switch (_currentStep)
        {
            case 0:
                <StepPersonalInfo FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                                  FullNameChanged="v => _fullName = v" EmailChanged="v => _email = v"
                                  PhoneChanged="v => _phone = v" AddressChanged="v => _address = v" />
                break;
            case 1:
                <StepWorkHistory Entries="_workEntries" />
                break;
            case 2:
                <StepReferences References="_references" />
                break;
            case 3:
                <StepCoverLetter Text="@_coverLetter" TextChanged="v => _coverLetter = v" MaxLength="2000" />
                break;
            case 4:
                <StepReview FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                            WorkEntries="_workEntries" References="_references" CoverLetter="@_coverLetter"
                            OnEditSection="GoToStep" />
                break;
        }

        <div class="d-flex justify-content-between mt-4">
            @if (_currentStep > 0)
            {
                <button class="btn btn-outline-secondary" @onclick="PreviousStep" disabled="@_isProcessing">Back</button>
            }
            else
            {
                <div></div>
            }

            @if (_currentStep < _stepNames.Length - 1)
            {
                <button class="btn btn-primary" @onclick="NextStep" disabled="@_isProcessing">
