@using static sv_bf53472deee14d2cbc3da8ad60301951.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">Work History</h4>

        @for (int i = 0; i < Entries.Count; i++)
        {
            var index = i;
            var entry = Entries[index];
            <div class="border rounded p-3 mb-3">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h6 class="mb-0">Position @(index + 1)</h6>
                    @if (Entries.Count > 1)
                    {
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveEntry(index)">Remove</button>
                    }
                </div>
                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Company <span class="text-danger">*</span></label>
                        <input class="form-control" value="@entry.Company" @oninput="e => entry.Company = e.Value?.ToString() ?? """/>
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Job Title <span class="text-danger">*</span></label>
                        <input class="form-control" value="@entry.Title" @oninput="e => entry.Title = e.Value?.ToString() ?? """/>
                    </div>
                </div>
                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Start Date <span class="text-danger">*</span></label>
                        <input type="date" class="form-control" value="@(entry.StartDate == default ? "" : entry.StartDate.ToString("yyyy-MM-dd"))"
                               @onchange="e => { if (DateTime.TryParse(e.Value?.ToString(), out var d)) entry.StartDate = d; }" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">End Date</label>
                        <input type="date" class="form-control" disabled="@entry.IsCurrent"
                               value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                               @onchange="e => { if (DateTime.TryParse(e.Value?.ToString(), out var d)) entry.EndDate = d; else entry.EndDate = null; }" />
                    </div>
                    <div class="col-md-4 d-flex align-items-end">
                        <div class="form-check mb-2">
                            <input type="checkbox" class="form-check-input" id="current-@index" checked="@entry.IsCurrent"
                                   @onchange="e => { entry.IsCurrent = (bool)(e.Value ?? false); if (entry.IsCurrent) entry.EndDate = null; }" />
                            <label class="form-check-label" for="current-@index">Currently working here</label>
                        </div>
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Description</label>
                    <textarea class="form-control" rows="2" @oninput="e => entry.Description = e.Value?.ToString() ?? """>@entry.Description</textarea>
                </div>
            </div>
        }

        <button class="btn btn-outline-primary" @onclick="AddEntry">
            + Add Another Position
        </button>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }
}

@using static sv_bf53472deee14d2cbc3da8ad60301951.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">References</h4>

        @for (int i = 0; i < References.Count; i++)
        {
            var index = i;
            var reference = References[index];
            <div class="border rounded p-3 mb-3">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h6 class="mb-0">Reference @(index + 1)</h6>
                    @if (References.Count > 2)
                    {
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(index)">Remove</button>
                    }
                </div>
                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Name <span class="text-danger">*</span></label>
                        <input class="form-control" value="@reference.Name" @oninput="e => reference.Name = e.Value?.ToString() ?? """  />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Relationship</label>
                        <input class="form-control" value="@reference.Relationship" @oninput="e => reference.Relationship = e.Value?.ToString() ?? """/>
                    </div>
                </div>
                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Email <span class="text-danger">*</span></label>
                        <input type="email" class="form-control" value="@reference.Email" @oninput="e => reference.Email = e.Value?.ToString() ?? """/>
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Phone</label>
                        <input type="tel" class="form-control" value="@reference.Phone" @oninput="e => reference.Phone = e.Value?.ToString() ?? """/>
                    </div>
                </div>
            </div>
        }

        @if (References.Count < 3)
        {
            <button class="btn btn-outline-primary" @onclick="AddReference">
                + Add Reference
            </button>
        }
    </div>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }
}
